<script lang="ts" setup>
import { Auth } from '@/src/http'
import { sleep } from '@antfu/utils'

// TODO: Add edgecase ui handler when emails are not available

const route = useRoute('/auth/google')
const loginSessionEmail = useSessionStorage('login-email', '')

onMounted(async () => {
  // Initiate login
  if (route.query.login_email) {
    loginSessionEmail.value = route.query.login_email as string
    location.href = Auth.createLoginURL(getRouteURL('/auth/google'))
  }

  // Authorize
  else {
    const success = await Auth.login(loginSessionEmail.value, route.query)

    // Wait for tokens to update watchers
    await sleep(500)

    if (success)
      window.close()
  }
})
</script>

<template>
  <div class="p-4 h-screen flex-col-center">
    <Spinner class="text-primary" />
  </div>
</template>

<route lang="yaml">
meta:
  auth: false
</route>
